import { useState, useRef, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { useLocation, useNavigate } from "react-router-dom";
import { Image, Video, X, Loader2, Calendar, MapPin, Gift, ArrowLeft } from "lucide-react";
import PostPointsRulesDialog from "./PostPointsRulesDialog";
import MultiRestaurantSelectDrawer from "./MultiRestaurantSelectDrawer";
import ActivitySelectDrawer from "./ActivitySelectDrawer";
import EmojiPicker from "./EmojiPicker";
import PostTypeSelector from "./PostTypeSelector";
import CreateRecipeWizard from "./recipe/CreateRecipeWizard";
import {
  Sheet,
  SheetContent,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { supabase } from "@/integrations/supabase/client";
import { useCreatePost, useMerchantRestaurant, useHasPostedToday } from "@/hooks/useCommunityPosts";
import { useActivities } from "@/hooks/useActivities";
import { useRestaurants } from "@/hooks/useRestaurants";
import { useUserRole } from "@/hooks/useUserRole";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { toast } from "sonner";
import * as VisuallyHidden from "@radix-ui/react-visually-hidden";

interface CreatePostDialogProps {
  trigger?: React.ReactNode;
}

/**
 * Mobile-only Sheet dialog for creating posts.
 * Desktop uses route-based pages (/community/create/*).
 */
const CreatePostDialog = ({ trigger }: CreatePostDialogProps) => {
  const { t } = useTranslation();
  const location = useLocation();
  const nav = useNavigate();
  const { getLocalizedField } = useLocalizedContent();
  const createPost = useCreatePost();
  const { data: activities } = useActivities();
  const { data: restaurants } = useRestaurants();
  const { isMerchant, isAdmin, isSupervisor } = useUserRole();
  const { data: merchantRestaurant } = useMerchantRestaurant();
  const { data: hasPostedToday, isLoading: checkingPost } = useHasPostedToday();

  const [open, setOpen] = useState(false);
  const [postType, setPostType] = useState<'selecting' | 'post' | 'recipe'>('selecting');

  useEffect(() => {
    const state = location.state as any;
    if (state?.openCreatePost) {
      setOpen(true);
      if (state.prefillPostType === 'post') {
        setPostType('post');
        if (state.prefillContent) setContent(state.prefillContent);
        if (state.prefillVideoUrl) setVideoUrl(state.prefillVideoUrl);
        if (state.prefillAiRecipeSource) setAiRecipeSource(state.prefillAiRecipeSource);
      } else {
        setPostType('selecting');
      }
      nav(location.pathname, { replace: true, state: {} });
    }
  }, [location.state]);

  const [content, setContent] = useState("");
  const [imageUrls, setImageUrls] = useState<string[]>([]);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [activityId, setActivityId] = useState<string>("");
  const [restaurantIds, setRestaurantIds] = useState<string[]>([]);
  const [uploading, setUploading] = useState(false);
  const [restaurantOpen, setRestaurantOpen] = useState(false);
  const [activityOpen, setActivityOpen] = useState(false);
  const [showRestaurantError, setShowRestaurantError] = useState(false);
  const [aiRecipeSource, setAiRecipeSource] = useState<Record<string, any> | null>(null);

  const imageInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  const isRegularUser = !isMerchant && !isSupervisor && !isAdmin;

  useEffect(() => {
    if (isMerchant && merchantRestaurant && open) {
      setRestaurantIds([merchantRestaurant.id]);
    }
  }, [isMerchant, merchantRestaurant, open]);

  const resetForm = () => {
    setPostType('selecting');
    setContent("");
    setImageUrls([]);
    setVideoUrl(null);
    setActivityId("");
    setRestaurantIds([]);
    setRestaurantOpen(false);
    setActivityOpen(false);
    setShowRestaurantError(false);
    setAiRecipeSource(null);
  };

  useEffect(() => {
    if (open) setPostType('selecting');
  }, [open]);

  const handleOpenChange = (newOpen: boolean) => {
    setOpen(newOpen);
    if (!newOpen) resetForm();
  };

  const activeActivities = activities?.filter((a) => a.status === "published") || [];

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    if (imageUrls.length + files.length > 9) {
      toast.error(t("community.maxImages", "最多上传9张图片"));
      return;
    }
    setUploading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");
      const uploadedUrls: string[] = [];
      for (const file of Array.from(files)) {
        const fileExt = file.name.split(".").pop();
        const fileName = `${user.id}/${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
        const { error: uploadError } = await supabase.storage.from("community-posts").upload(fileName, file);
        if (uploadError) throw uploadError;
        const { data: { publicUrl } } = supabase.storage.from("community-posts").getPublicUrl(fileName);
        uploadedUrls.push(publicUrl);
      }
      setImageUrls((prev) => [...prev, ...uploadedUrls]);
    } catch (error) {
      console.error("Upload error:", error);
      toast.error(t("common.uploadError", "上传失败"));
    } finally {
      setUploading(false);
      if (imageInputRef.current) imageInputRef.current.value = "";
    }
  };

  const extractVideoFirstFrame = (videoFile: File): Promise<Blob> => {
    return new Promise((resolve, reject) => {
      const video = document.createElement("video");
      const canvas = document.createElement("canvas");
      const ctx = canvas.getContext("2d");
      video.preload = "auto"; video.muted = true; video.playsInline = true;
      let hasResolved = false;
      const captureFrame = () => {
        if (hasResolved || video.videoWidth === 0) return;
        canvas.width = video.videoWidth; canvas.height = video.videoHeight;
        if (ctx) {
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
          canvas.toBlob((blob) => {
            if (blob && blob.size > 0) { hasResolved = true; video.pause(); URL.revokeObjectURL(video.src); resolve(blob); }
            else reject(new Error("Failed"));
          }, "image/jpeg", 0.85);
        }
      };
      video.onloadedmetadata = () => { video.currentTime = 0.1; };
      video.onseeked = () => { setTimeout(captureFrame, 100); };
      video.onerror = () => { URL.revokeObjectURL(video.src); reject(new Error("Failed")); };
      setTimeout(() => { if (!hasResolved) { URL.revokeObjectURL(video.src); reject(new Error("Timeout")); } }, 10000);
      video.src = URL.createObjectURL(videoFile); video.load();
    });
  };

  const handleVideoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 100 * 1024 * 1024) { toast.error(t("community.videoTooLarge", "视频不能超过100MB")); return; }
    setUploading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");
      const videoExt = file.name.split(".").pop();
      const videoFileName = `${user.id}/${Date.now()}.${videoExt}`;
      const { error: videoError } = await supabase.storage.from("community-posts").upload(videoFileName, file);
      if (videoError) throw videoError;
      const { data: { publicUrl: videoPublicUrl } } = supabase.storage.from("community-posts").getPublicUrl(videoFileName);
      setVideoUrl(videoPublicUrl);
      // Video cover is handled by the player itself (preload="metadata"), no need to save as image
    } catch (error) {
      console.error("Upload error:", error);
      toast.error(t("common.uploadError", "上传失败"));
    } finally {
      setUploading(false);
      if (videoInputRef.current) videoInputRef.current.value = "";
    }
  };

  const removeImage = (index: number) => setImageUrls((prev) => prev.filter((_, i) => i !== index));
  const removeVideo = () => {
    setVideoUrl(null);
  };

  const handleSubmit = async () => {
    setShowRestaurantError(false);
    if (!content.trim()) { toast.error(t("community.contentRequired", "请输入内容")); return; }
    if (isRegularUser && restaurantIds.length === 0) {
      setShowRestaurantError(true);
      toast.error(t("community.restaurantRequired", "请选择餐厅"));
      return;
    }
    await createPost.mutateAsync({
      content, image_urls: imageUrls, video_url: videoUrl || undefined,
      activity_id: activityId || undefined,
      restaurant_ids: restaurantIds.length > 0 ? restaurantIds : undefined,
      ai_recipe_source: aiRecipeSource || undefined,
    });
    resetForm();
    setOpen(false);
  };

  const getMerchantRestaurantName = () => {
    if (!merchantRestaurant) return t("community.noRestaurant", "未关联餐厅");
    return getLocalizedField(merchantRestaurant, "name");
  };

  return (
    <Sheet open={open} onOpenChange={handleOpenChange}>
      <SheetTrigger asChild>
        {trigger || <Button>{t("community.createPost", "发布帖子")}</Button>}
      </SheetTrigger>
      <SheetContent side="bottom" className="h-full flex flex-col p-0 rounded-none border-0 [&>button]:hidden">
        <VisuallyHidden.Root>
          <SheetTitle>{t("community.createPost", "发布帖子")}</SheetTitle>
        </VisuallyHidden.Root>

        {/* Type Selection */}
        {postType === 'selecting' && (
          <div className="h-full flex flex-col">
            <div className="flex items-center justify-between px-4 py-3 border-b bg-background shrink-0">
              <button type="button" onClick={() => setOpen(false)} className="p-1 -ml-1 hover:bg-muted rounded-md transition-colors">
                <ArrowLeft className="h-5 w-5" />
              </button>
              <span className="font-medium">{t("community.create", "发布")}</span>
              <div className="w-6" />
            </div>
            <PostTypeSelector onSelect={setPostType} />
          </div>
        )}

        {/* Recipe */}
        {postType === 'recipe' && (
          <CreateRecipeWizard onClose={() => setPostType('selecting')} onSuccess={() => { resetForm(); setOpen(false); }} />
        )}

        {/* Regular Post */}
        {postType === 'post' && (
          <>
            <input ref={imageInputRef} type="file" accept="image/*" multiple className="hidden" onChange={handleImageUpload} />
            <input ref={videoInputRef} type="file" accept="video/*" className="hidden" onChange={handleVideoUpload} />

            {/* Header */}
            <div className="flex items-center justify-between px-4 py-3 border-b bg-background shrink-0">
              <button type="button" onClick={() => setPostType('selecting')} className="p-1 -ml-1 hover:bg-muted rounded-md transition-colors">
                <ArrowLeft className="h-5 w-5" />
              </button>
              <Button size="sm" onClick={handleSubmit} disabled={createPost.isPending || !content.trim()} className="rounded-full px-6">
                {createPost.isPending && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
                {t("community.publish", "发布")}
              </Button>
            </div>

            {/* Points hint */}
            {!checkingPost && !hasPostedToday && (
              <div className="flex items-center justify-between gap-2 px-4 py-2 bg-primary/10 dark:bg-primary/20 border-b border-primary/30 dark:border-primary/40 text-sm text-primary shrink-0">
                <div className="flex items-center gap-2">
                  <Gift className="h-4 w-4 shrink-0" />
                  <span>{t("community.dailyPointsHint", "每日发布首个帖子可获得5积分！")}</span>
                </div>
                <PostPointsRulesDialog />
              </div>
            )}

            {/* Content area */}
            <div className="flex-1 flex flex-col overflow-hidden min-h-0">
              {/* Text */}
              <div className="flex-1 flex flex-col overflow-hidden order-1">
                <div className="flex-1 overflow-y-auto p-4">
                  <Textarea
                    value={content}
                    onChange={(e) => setContent(e.target.value)}
                    placeholder={t("community.contentPlaceholder", "分享你的想法...")}
                    className="min-h-[120px] h-full border-none shadow-none resize-none focus-visible:ring-0 p-0 text-base whitespace-pre-wrap"
                  />
                </div>
              </div>

              {/* Media preview */}
              {(imageUrls.length > 0 || videoUrl) && (
                <div className="order-2 bg-muted/20 overflow-hidden shrink-0">
                  <div className="overflow-y-auto p-3 space-y-3 max-h-[200px]">
                    {imageUrls.length > 0 && (
                      <div className="flex gap-2 overflow-x-auto pb-1">
                        {imageUrls.map((url, index) => (
                          <div key={index} className="relative aspect-square rounded-lg overflow-hidden bg-muted shrink-0 w-20 h-20">
                            <img src={url} alt="" className="w-full h-full object-cover" />
                            <button type="button" onClick={() => removeImage(index)} className="absolute top-1 right-1 p-1 bg-black/50 rounded-full text-white hover:bg-black/70">
                              <X className="h-3 w-3" />
                            </button>
                          </div>
                        ))}
                      </div>
                    )}
                    {videoUrl && (
                      <div className="relative rounded-lg overflow-hidden">
                        <video src={videoUrl} controls className="w-full max-h-[160px]" preload="metadata" />
                        <button type="button" onClick={removeVideo} className="absolute top-2 right-2 p-1 bg-black/50 rounded-full text-white hover:bg-black/70">
                          <X className="h-4 w-4" />
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              )}

              {/* Bottom toolbar */}
              <div className="order-3 border-t bg-background shrink-0">
                <div className="px-4 py-2 space-y-2">
                  <div className="flex items-center gap-4 flex-wrap">
                    <EmojiPicker onSelect={(emoji) => setContent((prev) => prev + emoji)} />
                    <div className={`flex items-center gap-2 ${showRestaurantError && isRegularUser && restaurantIds.length === 0 ? 'text-destructive' : ''}`}>
                      <MapPin className={`h-4 w-4 shrink-0 ${showRestaurantError && isRegularUser && restaurantIds.length === 0 ? 'text-destructive' : 'text-muted-foreground'}`} />
                      {isMerchant ? (
                        <span className="text-sm text-muted-foreground">{getMerchantRestaurantName()}</span>
                      ) : (
                        <MultiRestaurantSelectDrawer
                          open={restaurantOpen}
                          onOpenChange={(open) => { setRestaurantOpen(open); if (open) setShowRestaurantError(false); }}
                          value={restaurantIds}
                          onSelect={(ids) => { setRestaurantIds(ids); setShowRestaurantError(false); }}
                          restaurants={restaurants || []}
                          required={isRegularUser}
                        />
                      )}
                    </div>
                    <div className="flex items-center gap-2">
                      <Calendar className="h-4 w-4 text-muted-foreground shrink-0" />
                      <ActivitySelectDrawer open={activityOpen} onOpenChange={setActivityOpen} value={activityId} onSelect={setActivityId} activities={activeActivities} />
                    </div>
                  </div>
                  {showRestaurantError && isRegularUser && restaurantIds.length === 0 && (
                    <p className="text-xs text-destructive">{t("community.restaurantRequired", "请选择餐厅")}</p>
                  )}
                </div>
                <div className="flex items-center gap-4 px-4 py-3 border-t pb-[max(0.75rem,env(safe-area-inset-bottom))]">
                  <button type="button" onClick={() => imageInputRef.current?.click()} disabled={uploading || imageUrls.length >= 9} className="flex items-center gap-1.5 text-muted-foreground hover:text-foreground disabled:opacity-50 transition-colors">
                    <Image className="h-5 w-5" />
                    <span className="text-xs">{t("community.photo", "照片")}</span>
                  </button>
                  <button type="button" onClick={() => videoInputRef.current?.click()} disabled={uploading || !!videoUrl} className="flex items-center gap-1.5 text-muted-foreground hover:text-foreground disabled:opacity-50 transition-colors">
                    <Video className="h-5 w-5" />
                    <span className="text-xs">{t("community.video", "视频")}</span>
                  </button>
                  {uploading && <Loader2 className="h-4 w-4 animate-spin ml-auto text-muted-foreground" />}
                </div>
              </div>
            </div>
          </>
        )}
      </SheetContent>
    </Sheet>
  );
};

export default CreatePostDialog;
